Bash(node -e "
const BASE = 'https://bloomleave.com';
async function run\(\) {
  const adminLogin = await fetch\(BASE + '/api/auth/login', {
    method: 'POST', headers: {'Content-Type': 'application/json'},
    body: JSON.stringify\({ email: 'josh@bloomandgrowgroup.com', password: 'C00k1eD0g' }\)
  }\);
  const { data } = await adminLogin.json\(\);
  const token = data.accessToken;

  // Get all users with their manager IDs  
  const res = await fetch\(BASE + '/api/users?pageSize=100', { headers: { Authorization: 'Bearer ' + token } }\);
  const d = await res.json\(\);
  const users = d.data?.users || d.data || [];

  // Find eva.chan and trace manager chain
  const eva = users.find\(u => u.email === 'eva.chan@bloomandgrowgroup.com'\);
  console.log\('Eva:', eva?.id, 'managerId:', eva?.managerId\);

  // Find amy  
  const amy = users.find\(u => u.email === 'amy@bloomandgrowgroup.com'\);
  console.log\('Amy:', amy?.id, 'managerId:', amy?.managerId\);

  // Build manager map
  const userMap = {};
  users.forEach\(u => userMap[u.id] = { name: u.name, managerId: u.managerId }\);

  // Trace chain for eva
  let current = eva;
  let chain = [eva?.id];
  let steps = 0;
  while \(current?.managerId && steps < 10\) {
    current = userMap[current.managerId];
    chain.push\(current?.id\);
    steps++;
    if \(chain.slice\(0,-1\).includes\(current?.id\)\) { console.log\('CIRCULAR REFERENCE DETECTED!', chain\); break; }
  }
  console.log\('Eva manager chain:', chain\);
}
run\(\).catch\(console.error\);
")
